  1→import React, { useState, useMemo, useEffect } from 'react';
  2→import { Project, User, AnalysisResult, GeneratedSolution } from '../types';
  3→import { Plus, Search, Globe, TrendingUp, Calendar, ArrowUpRight, BarChart3, ChevronDown, Zap, Activity, ArrowRight, Wrench, FileText, Shield, ExternalLink, Clock, LayoutDashboard, Bot, Lock, ChevronLeft, ChevronRight, Eye, RefreshCw, ClipboardList, ArrowLeft, ClipboardCheck, Archive, Code, ArrowUp, ArrowDown, CheckCircle2, XCircle, GitCompareArrows } from 'lucide-react';
  4→import ScoreRing from '../components/ScoreRing';
  5→import EngineBreakdown from '../components/EngineBreakdown';
  6→import { calculateEngineScores } from '../lib/engine-score-calculator';
  7→import { mapAnalysisResults, CRITERIA_LABELS } from '../lib/criteria-mapper';
  8→import { ENGINE_PROFILES } from '../config/engine-weights';
  9→import { Results } from './Results';
 10→import ActionPlan from './ActionPlan';
 11→import GenerationModal from '../components/GenerationModal';
 12→
 13→interface ProjectsProps {
 14→  onBack: () => void;
 15→  onNavigateToAnalysis: () => void;
 16→  user: User | null;
 17→  history: AnalysisResult[];
 18→  onViewAnalysis: (result: AnalysisResult, tab: 'overview' | 'details' | 'recommendations' | 'preview') => void;
 19→  projectCount: number;
 20→  maxProjects: number;
 21→  onNavigateToPlan: () => void;
 22→  onDeductCredits: (amount: number) => boolean;
 23→  onSaveSolution: (analysisId: string, recId: string, solution: GeneratedSolution) => void;
 24→  onNewAnalysis: () => void;
 25→  onNavigateToRecharge: () => void;
 26→  initialUrl?: string;
 27→  initialTab?: string;
 28→}
 29→
 30→// Helper to convert AnalysisResult to Project format
 31→const mapAnalysisToProject = (analysis: AnalysisResult, index: number): Project => {
 32→  const hostname = new URL(analysis.url).hostname;
 33→  return {
 34→    id: `proj_${index}_${hostname}`,
 35→    name: hostname,
 36→    domain: analysis.url,
 37→    status: 'active',
 38→    lastRun: analysis.timestamp,
 39→    visibilityScore: analysis.globalScore,
 40→    trend: analysis.globalScore > 70 ? 12 : (analysis.globalScore > 50 ? 5 : -5), // Simulé basé sur le score
 41→    nextRun: new Date(new Date(analysis.timestamp).getTime() + 86400000 * 7).toISOString()
 42→  };
 43→};
 44→
 45→const Projects: React.FC<ProjectsProps> = ({ onBack, onNavigateToAnalysis, user, history, onViewAnalysis, projectCount, maxProjects, onNavigateToPlan, onDeductCredits, onSaveSolution, onNewAnalysis, onNavigateToRecharge, initialUrl, initialTab }) => {
 46→  // Navigation internal state: monitoring | report | action-plan | rescan | archives
 47→  const [activeTab, setActiveTab] = useState<'monitoring' | 'report' | 'action-plan' | 'rescan' | 'archives'>(() => {
 48→    if (initialTab === 'archives') return 'archives';
 49→    if (initialTab === 'recommendations' || initialTab === 'action-plan') return 'action-plan';
 50→    if (initialTab === 'details' || initialTab === 'report') return 'report';
 51→    return 'monitoring';
 52→  });
 53→
 54→  useEffect(() => {
 55→    if (initialTab === 'archives') setActiveTab('archives');
 56→    else if (initialTab === 'recommendations') setActiveTab('action-plan');
 57→    else if (initialTab === 'details' || initialTab === 'report') setActiveTab('report');
 58→    else if (initialTab === 'overview') setActiveTab('monitoring');
 59→  }, [initialTab]);
 60→
 61→  // Use history to build project list, defaulting to mock if empty for demo
 62→  const projects = useMemo(() => {
 63→    if (history.length > 0) {
 64→      // Deduplicate by URL hostname, keeping the most recent
 65→      const uniqueMap = new Map<string, AnalysisResult>();
 66→      history.forEach(item => {
 67→        try {
 68→            const host = new URL(item.url).hostname;
 69→            if (!uniqueMap.has(host) || new Date(item.timestamp) > new Date(uniqueMap.get(host)!.timestamp)) {
 70→                uniqueMap.set(host, item);
 71→            }
 72→        } catch(e) {}
 73→      });
 74→      return Array.from(uniqueMap.values()).map((analysis, index) => mapAnalysisToProject(analysis, index));
 75→    } else {
 76→      // Mock data fallback if no history
 77→      return [
 78→        {
 79→          id: 'demo_1',
 80→          name: 'Exemple Site Demo',
 81→          domain: 'https://demo-site.com',
 82→          status: 'active',
 83→          lastRun: new Date().toISOString(),
 84→          visibilityScore: 45,
 85→          trend: 0,
 86→          nextRun: new Date(Date.now() + 86400000).toISOString()
 87→        }
 88→      ] as Project[];
 89→    }
 90→  }, [history]);
 91→
 92→  const [selectedProjectId, setSelectedProjectId] = useState<string>(() => {
 93→    if (initialUrl && projects.length > 0) {
 94→        try {
 95→            const targetHost = new URL(initialUrl).hostname;
 96→            // The projects mapping uses hostname as name
 97→            const found = projects.find(p => p.name === targetHost);
 98→            if (found) return found.id;
 99→        } catch(e) {}
100→    }
101→    return projects[0]?.id || '';
102→  });
103→
104→  const [selectedAnalysisState, setSelectedAnalysisState] = useState<AnalysisResult | null>(null);
105→  
106→  // States for viewing archive modal
107→  const [isModalOpen, setIsModalOpen] = useState(false);
108→  const [currentSolution, setCurrentSolution] = useState<GeneratedSolution | null>(null);
109→
110→  const currentProject = projects.find(p => p.id === selectedProjectId) || projects[0];
111→  
112→  // Filter history for current project ONLY
113→  const projectHistory = useMemo(() => {
114→    return history
115→      .filter(h => {
116→          try { return new URL(h.url).hostname === currentProject.name; }
117→          catch(e) { return false; }
118→      })
119→      .sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());
120→  }, [history, currentProject]);
121→
122→  // Reset selected analysis when project changes
123→  useEffect(() => {
124→    setSelectedAnalysisState(null);
125→  }, [selectedProjectId]);
126→
127→  // The analysis to display (either user-selected from table, or the latest one)
128→  const activeAnalysis = selectedAnalysisState || projectHistory[0];
129→
130→  const handleOpenStoredSolution = (solution: GeneratedSolution) => {
131→    setCurrentSolution(solution);
132→    setIsModalOpen(true);
133→  };
134→
135→  // Calculate Pillar Scores from real categories if available
136→  const getPillarScores = () => {
137→    if (!activeAnalysis) {
138→      return {
139→        tech: 50,
140→        sem: 50,
141→        auth: 50
142→      };
143→    }
144→    
145→    const cats = activeAnalysis.categories;
146→    
147→    // Aggregation logic
148→    const techScore = Math.round(
149→      ((cats['technical']?.score || 0) + (cats['ux']?.score || 0) + (cats['freshness']?.score || 0)) / 3
150→    );
151→    
152→    const semScore = Math.round(
153→      ((cats['semantic']?.score || 0) + (cats['content']?.score || 0) + (cats['geo']?.score || 0) + (cats['media']?.score || 0)) / 4
154→    );
155→    
156→    const authScore = Math.round(
157→      ((cats['entity']?.score || 0) + (cats['structured_data']?.score || 0) + (cats['trust']?.score || 0)) / 3
158→    );
159→
160→    return { tech: techScore, sem: semScore, auth: authScore };
161→  };
162→
163→  const pillarScores = getPillarScores();
164→
165→  // Engine scores for monitoring tab
166→  const engineScores = useMemo(() => {
167→    if (!activeAnalysis) return [];
168→    const criteriaResults = mapAnalysisResults(activeAnalysis);
169→    return calculateEngineScores(criteriaResults);
170→  }, [activeAnalysis]);
171→
172→  // Comparison data between two most recent analyses
173→  const comparisonData = useMemo(() => {
174→    if (projectHistory.length < 2) return null;
175→    const latest = projectHistory[0];
176→    const previous = projectHistory[1];
177→
178→    const latestCriteria = mapAnalysisResults(latest);
179→    const previousCriteria = mapAnalysisResults(previous);
180→    const latestEngines = calculateEngineScores(latestCriteria);
181→    const previousEngines = calculateEngineScores(previousCriteria);
182→
183→    const engineDeltas = latestEngines.map(le => {
184→      const pe = previousEngines.find(p => p.engineId === le.engineId);
185→      return {
186→        engineId: le.engineId,
187→        engineName: le.engineName,
188→        engineIcon: le.engineIcon,
189→        engineColor: le.engineColor,
190→        before: pe?.score ?? 0,
191→        after: le.score,
192→        delta: le.score - (pe?.score ?? 0),
193→      };
194→    });
195→
196→    // Find fixed & regressed criteria
197→    const fixed: string[] = [];
198→    const regressed: string[] = [];
199→    latestCriteria.forEach(lc => {
200→      const pc = previousCriteria.find(p => p.id === lc.id);
201→      if (pc && !pc.passed && lc.passed) fixed.push(lc.id);
202→      if (pc && pc.passed && !lc.passed) regressed.push(lc.id);
203→    });
204→
205→    return {
206→      latest,
207→      previous,
208→      globalDelta: latest.globalScore - previous.globalScore,
209→      engineDeltas,
210→      fixed,
211→      regressed,
212→    };
213→  }, [projectHistory]);
214→
215→  const getScoreColor = (score: number) => {
216→    if (score >= 80) return 'text-white'; // Purple implied by bg bar
217→    if (score >= 60) return 'text-purple-400';
218→    return 'text-blue-400'; // For variation
219→  };
220→
221→  const getBarColor = (score: number) => {
222→    if (score >= 80) return 'bg-purple-400';
223→    if (score >= 60) return 'bg-purple-500';
224→    return 'bg-blue-400';
225→  };
226→
227→  const handleSwitchToReport = () => {
228→    if (activeAnalysis) {
229→        setActiveTab('report');
230→    } else {
231→        alert("Veuillez lancer une analyse pour voir le rapport.");
232→        onNavigateToAnalysis();
233→    }
234→  };
235→
236→  const handleSwitchToActionPlan = () => {
237→    if (activeAnalysis) {
238→        setActiveTab('action-plan');
239→    } else {
240→        alert("Veuillez lancer une analyse pour voir le plan d'action.");
241→        onNavigateToAnalysis();
242→    }
243→  };
244→
245→  const handleSwitchToRescan = () => {
246→    if (activeAnalysis) {
247→        setActiveTab('rescan');
248→    } else {
249→        alert("Veuillez lancer une analyse pour voir le suivi.");
250→        onNavigateToAnalysis();
251→    }
252→  };
253→
254→  const handleSwitchToArchives = () => {
255→    if (activeAnalysis) {
256→        setActiveTab('archives');
257→    } else {
258→        alert("Veuillez lancer une analyse pour voir les archives.");
259→        onNavigateToAnalysis();
260→    }
261→  };
262→
263→  const handleBackToMonitoring = () => {
264→    setActiveTab('monitoring');
265→  };
266→
267→  const isLimitReached = projectCount >= maxProjects;
268→
269→  // -- SHARED TABS BAR (rendered on all views) --
270→  const [isProjectDropdownOpen, setIsProjectDropdownOpen] = useState(false);
271→
272→  const renderTabsBar = () => (
273→    <div className="w-full px-4 pt-8">
274→      {/* URL Selector — prominent, above tabs */}
275→      <div className="flex flex-col sm:flex-row items-start sm:items-center gap-3 mb-6">
276→        <div className="relative">
277→          <button
278→            onClick={() => setIsProjectDropdownOpen(!isProjectDropdownOpen)}
279→            className="flex items-center gap-3 px-5 py-2.5 bg-gradient-to-r from-purple-500/10 to-violet-500/10 hover:from-purple-500/20 hover:to-violet-500/20 border border-purple-500/30 rounded-2xl transition-all text-sm font-bold group"
280→          >
281→            <Globe size={16} className="text-purple-400" />
282→            <span className="text-white truncate max-w-[280px]">{currentProject.name}</span>
283→            <ChevronDown size={14} className={`text-purple-400 transition-transform ${isProjectDropdownOpen ? 'rotate-180' : ''}`} />
284→          </button>
285→          {isProjectDropdownOpen && (
286→            <>
287→              <div className="fixed inset-0 z-40" onClick={() => setIsProjectDropdownOpen(false)} />
288→              <div className="absolute top-full left-0 mt-2 w-72 bg-[#1a1d24] border border-purple-500/20 rounded-2xl shadow-2xl shadow-purple-500/10 z-50 p-1.5 animate-in fade-in slide-in-from-top-2 duration-200">
289→                <p className="px-3 py-1.5 text-[10px] uppercase tracking-wider text-gray-500 font-bold">Projets scannés</p>
290→                {projects.map(p => (
291→                  <button
292→                    key={p.id}
293→                    onClick={() => { setSelectedProjectId(p.id); setIsProjectDropdownOpen(false); }}
294→                    className={`w-full text-left px-3 py-2.5 rounded-xl text-sm flex items-center gap-2.5 transition-colors ${
295→                      p.id === selectedProjectId
296→                        ? 'bg-purple-500/15 text-purple-300 font-bold'
297→                        : 'text-gray-300 hover:bg-white/[0.06]'
298→                    }`}
299→                  >
300→                    <Globe size={14} className={p.id === selectedProjectId ? 'text-purple-400' : 'text-gray-600'} />
301→                    {p.name}
302→                  </button>
303→                ))}
304→                <div className="border-t border-white/[0.06] mt-1.5 pt-1.5">
305→                  <button
306→                    onClick={() => { setIsProjectDropdownOpen(false); onNavigateToAnalysis(); }}
307→                    className="w-full text-left px-3 py-2.5 rounded-xl text-sm text-gray-500 hover:text-white hover:bg-white/[0.06] flex items-center gap-2.5 transition-colors"
308→                  >
309→                    <Plus size={14} /> Scanner une nouvelle URL
310→                  </button>
311→                </div>
312→              </div>
313→            </>
314→          )}
315→        </div>
316→        {currentProject && (
317→          <span className="text-xs text-gray-500 flex items-center gap-1.5">
318→            <span className="w-1.5 h-1.5 bg-purple-400 rounded-full animate-pulse"></span>
319→            Monitoring actif
320→          </span>
321→        )}
322→      </div>
323→
324→      {/* Tabs */}
325→      <div className="flex gap-6 mb-8 border-b border-white/[0.08] overflow-x-auto">
326→          <button
327→            onClick={() => setActiveTab('monitoring')}
328→            className={`pb-3 px-4 text-sm font-bold border-b-2 transition-all duration-200 flex items-center gap-2 whitespace-nowrap ${
329→              activeTab === 'monitoring'
330→                ? 'border-primary text-white'
331→                : 'border-transparent text-gray-500 hover:text-gray-300'
332→            }`}
333→          >
334→            <Activity size={18} className={activeTab === 'monitoring' ? 'text-purple-400' : 'opacity-50'} />
335→            Vue d'ensemble
336→          </button>
337→
338→          <button
339→            onClick={handleSwitchToReport}
340→            className={`pb-3 px-4 text-sm font-bold border-b-2 transition-all duration-200 flex items-center gap-2 whitespace-nowrap ${
341→              activeTab === 'report'
342→                ? 'border-primary text-white'
343→                : 'border-transparent text-gray-500 hover:text-gray-300'
344→            }`}
345→          >
346→            <ClipboardList size={18} className={activeTab === 'report' ? 'text-purple-400' : 'opacity-50'} />
347→            Rapport d'Audit
348→          </button>
349→
350→          <button
351→            onClick={handleSwitchToActionPlan}
352→            className={`pb-3 px-4 text-sm font-bold border-b-2 transition-all duration-200 flex items-center gap-2 whitespace-nowrap ${
353→              activeTab === 'action-plan'
354→                ? 'border-primary text-white'
355→                : 'border-transparent text-gray-500 hover:text-gray-300'
356→            }`}
357→          >
358→            <Zap size={18} className={activeTab === 'action-plan' ? 'text-purple-400 fill-primary' : 'opacity-50'} />
359→            Plan d'Action
360→            {activeAnalysis && activeAnalysis.recommendations.length > 0 && (
361→                <span className="bg-primary text-black text-[10px] px-1.5 py-0.5 rounded-full ml-1.5">
362→                    {activeAnalysis.recommendations.length}
363→                </span>
364→            )}
365→          </button>
366→
367→          <button
368→            onClick={handleSwitchToRescan}
369→            className={`pb-3 px-4 text-sm font-bold border-b-2 transition-all duration-200 flex items-center gap-2 whitespace-nowrap ${
370→              activeTab === 'rescan'
371→                ? 'border-primary text-white'
372→                : 'border-transparent text-gray-500 hover:text-gray-300'
373→            }`}
374→          >
375→            <GitCompareArrows size={18} className={activeTab === 'rescan' ? 'text-purple-400' : 'opacity-50'} />
376→            Re-scan & Suivi
377→            {comparisonData && comparisonData.globalDelta !== 0 && (
378→              <span className={`text-[10px] px-1.5 py-0.5 rounded-full ml-1 font-bold ${
379→                comparisonData.globalDelta > 0 ? 'bg-green-500/20 text-green-400' : 'bg-red-500/20 text-red-400'
380→              }`}>
381→                {comparisonData.globalDelta > 0 ? '+' : ''}{comparisonData.globalDelta}
382→              </span>
383→            )}
384→          </button>
385→
386→          <button
387→            onClick={handleSwitchToArchives}
388→            className={`pb-3 px-4 text-sm font-bold border-b-2 transition-all duration-200 flex items-center gap-2 whitespace-nowrap ${
389→              activeTab === 'archives'
390→                ? 'border-primary text-white'
391→                : 'border-transparent text-gray-500 hover:text-gray-300'
392→            }`}
393→          >
394→            <Archive size={18} className={activeTab === 'archives' ? 'text-purple-400' : 'opacity-50'} />
395→            Archives Solutions
396→          </button>
397→      </div>
398→    </div>
399→  );
400→
401→  // -- RENDER : REPORT VIEW (RESULTS) --
402→  if (activeTab === 'report' && activeAnalysis) {
403→      return (
404→          <div className="animate-in fade-in slide-in-from-right-4 duration-300">
405→              {renderTabsBar()}
406→              <Results 
407→                data={activeAnalysis} 
408→                onBack={handleBackToMonitoring}
409→                user={user}
410→                onDeductCredits={onDeductCredits}
411→                onSaveSolution={onSaveSolution}
412→                onNewAnalysis={onNewAnalysis}
413→              />
414→          </div>
415→      );
416→  }
417→
418→  // -- RENDER : ACTION PLAN VIEW --
419→  if (activeTab === 'action-plan' && activeAnalysis) {
420→      return (
421→          <div className="animate-in fade-in slide-in-from-right-4 duration-300">
422→              {renderTabsBar()}
423→              <ActionPlan 
424→                data={activeAnalysis}
425→                user={user}
426→                onDeductCredits={onDeductCredits}
427→                onSaveSolution={onSaveSolution}
428→                onNavigateToAnalysis={onNewAnalysis}
429→                onNavigateToRecharge={onNavigateToRecharge}
430→              />
431→          </div>
432→      );
433→  }
434→
435→  // -- RENDER : RE-SCAN & SUIVI VIEW --
436→  if (activeTab === 'rescan' && activeAnalysis) {
437→      return (
438→          <div className="animate-in fade-in slide-in-from-right-4 duration-300 w-full">
439→              {renderTabsBar()}
440→              <div className="px-4 pb-8">
441→                <div className="flex items-center justify-between mb-8">
442→                  <div className="flex items-center gap-3">
443→                    <div className="w-10 h-10 rounded-full bg-purple-500/20 flex items-center justify-center text-purple-300 border border-purple-500/30">
444→                        <GitCompareArrows size={20} />
445→                    </div>
446→                    <div>
447→                        <h3 className="text-xl font-sans font-bold text-white">Re-scan & Suivi</h3>
448→                        <p className="text-sm text-gray-500">Comparez vos audits et mesurez la progression de vos optimisations.</p>
449→                    </div>
450→                  </div>
451→                  <button
452→                    onClick={onNavigateToAnalysis}
453→                    className="px-4 py-2.5 bg-gradient-to-r from-purple-500 to-violet-600 text-white font-bold rounded-2xl hover:from-purple-600 hover:to-violet-700 transition-colors text-sm flex items-center gap-2 shadow-lg shadow-primary/20"
454→                  >
455→                    <RefreshCw size={16} /> Lancer un re-scan
456→                  </button>
457→                </div>
458→
459→                {/* Before / After comparison */}
460→                {comparisonData ? (
461→                  <>
462→                    {/* Global score comparison */}
463→                    <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
464→                      {/* Before */}
465→                      <div className="ninja-card p-6 rounded-2xl border border-white/[0.08] flex flex-col items-center">
466→                        <p className="text-xs text-gray-500 uppercase tracking-wider mb-3 font-medium">Audit précédent</p>
467→                        <p className="text-[10px] text-gray-600 mb-2">{new Date(comparisonData.previous.timestamp).toLocaleDateString()}</p>
468→                        <ScoreRing score={comparisonData.previous.globalScore} size={110} strokeWidth={8} noAnimation />
469→                      </div>
470→
471→                      {/* Delta */}
472→                      <div className="ninja-card p-6 rounded-2xl border border-white/[0.08] flex flex-col items-center justify-center">
473→                        <p className="text-xs text-gray-500 uppercase tracking-wider mb-4 font-medium">Progression</p>
474→                        <div className={`text-4xl font-bold ${comparisonData.globalDelta > 0 ? 'text-green-400' : comparisonData.globalDelta < 0 ? 'text-red-400' : 'text-gray-400'}`}>
475→                          {comparisonData.globalDelta > 0 ? '+' : ''}{comparisonData.globalDelta}
476→                        </div>
477→                        <div className="flex items-center gap-1 mt-2">
478→                          {comparisonData.globalDelta > 0 && <ArrowUp size={16} className="text-green-400" />}
479→                          {comparisonData.globalDelta < 0 && <ArrowDown size={16} className="text-red-400" />}
480→                          <span className="text-sm text-gray-500">points</span>
481→                        </div>
482→                      </div>
483→
484→                      {/* After */}
485→                      <div className="ninja-card p-6 rounded-2xl border border-purple-500/20 flex flex-col items-center bg-purple-500/5">
486→                        <p className="text-xs text-purple-400 uppercase tracking-wider mb-3 font-medium">Dernier audit</p>
487→                        <p className="text-[10px] text-gray-600 mb-2">{new Date(comparisonData.latest.timestamp).toLocaleDateString()}</p>
488→                        <ScoreRing score={comparisonData.latest.globalScore} size={110} strokeWidth={8} noAnimation />
489→                      </div>
490→                    </div>
491→
492→                    {/* Engine deltas */}
493→                    <div className="ninja-card p-6 rounded-2xl border border-white/[0.08] mb-8">
494→                      <h4 className="text-sm font-bold text-white mb-4 flex items-center gap-2">
495→                        <BarChart3 size={16} className="text-purple-400" />
496→                        Progression par moteur IA
497→                      </h4>
498→                      <div className="space-y-4">
499→                        {comparisonData.engineDeltas.map(ed => (
500→                          <div key={ed.engineId} className="flex items-center gap-4">
501→                            <div className="flex items-center gap-2 w-40 shrink-0">
502→                              <span className="text-lg">{ed.engineIcon}</span>
503→                              <span className="text-sm text-white font-medium truncate">{ed.engineName}</span>
504→                            </div>
505→                            <div className="flex-1">
506→                              <div className="flex items-center gap-3">
507→                                <span className="text-xs text-gray-500 w-8 text-right">{ed.before}</span>
508→                                <div className="flex-1 h-2 bg-white/10 rounded-full overflow-hidden relative">
509→                                  <div
510→                                    className="h-full rounded-full absolute left-0 top-0 opacity-30"
511→                                    style={{ width: `${ed.before}%`, backgroundColor: ed.engineColor }}
512→                                  />
513→                                  <div
514→                                    className="h-full rounded-full absolute left-0 top-0"
515→                                    style={{ width: `${ed.after}%`, backgroundColor: ed.engineColor }}
516→                                  />
